        }

        def Xform "ChairB"
        {
            reference = </Assets/Chair>
            double3 xformOp:translate = (2, 0, 0)
            string[] xformOpOrder = ["xformOp:translate"]
        }
    }

    def Xform "Lighting"
    {
        variantSet "lightingVariant"
        {
            variant "day"
            {
                def DistantLight "Sun"
                {
                    float intensity = 50000
                }
            }

            variant "night"
            {
                def DomeLight "Sky"
                {
                    float intensity = 500
                }
            }
        }
    }
}
